//! # TemplateFlow
//!
//! A Rust client for accessing standardized brain templates from TemplateFlow.
//!
//! TemplateFlow provides access to a library of standardized brain templates
//! used in neuroimaging research. This crate provides a Rust interface to
//! download and query these templates.
//!
//! ## Features
//!
//! - List available templates and their metadata
//! - Download template files from S3
//! - Query templates using BIDS entities
//! - Local caching of downloaded templates
//! - Async/sync API support
//!
//! ## Example
//!
//! ```rust,no_run
//! use templateflow::{get, QueryParams};
//!
//! # fn main() -> Result<(), Box<dyn std::error::Error>> {
//! // Download a specific template file
//! let params = QueryParams {
//!     resolution: Some(1),
//!     suffix: Some("T1w".to_string()),
//!     ..Default::default()
//! };
//!
//! let file_path = get("MNI152NLin2009cAsym", params)?;
//! println!("Downloaded template to: {:?}", file_path);
//! # Ok(())
//! # }
//! ```

// Public modules
pub mod error;
pub mod config;
pub mod s3;
pub mod cache;
pub mod bids;
pub mod api;
pub mod cli;

// Re-export commonly used types
pub use error::{TemplateFlowError, Result};
pub use config::Config;
pub use bids::TemplateMetadata;

// Re-export API functions
pub use api::{get, get_metadata, get_citations, ls, templates};
// Re-export async API functions
pub use api::{get_async, get_multiple_async};

