    10→use crate::bids::{TemplateLayout, TemplateMetadata};
    11→use crate::config::CONFIG;
    12→use crate::error::{Result, TemplateFlowError};
    13→use crate::s3;
    14→use once_cell::sync::Lazy;
    15→use std::collections::HashMap;
    16→use std::path::PathBuf;
    17→use std::sync::{Arc, Mutex};
    18→
    19→/// Global template layout instance
    20→static LAYOUT: Lazy<Arc<Mutex<Option<TemplateLayout>>>> = Lazy::new(|| Arc::new(Mutex::new(None)));
    21→
    22→/// Ensure the layout is loaded
    23→fn ensure_layout() -> Result<()> {
    24→    let mut layout_guard = LAYOUT.lock().unwrap();
    25→    
    26→    if layout_guard.is_none() {
    27→        // Download skeleton if needed
    28→        let skeleton_path = CONFIG.skeleton_path();
    29→        if !skeleton_path.exists() {
    30→            s3::update_skeleton_sync()?;
    31→        }
    32→        
    33→        // Load the layout
    34→        let layout = crate::bids::load_skeleton_from_file(&skeleton_path)?;
    35→        *layout_guard = Some(layout);
    36→    }
    37→    
    38→    Ok(())
    39→}
    40→
    41→/// Get template metadata
    42→///
    43→/// # Arguments
    44→/// * `template` - Template identifier (e.g., "MNI152Lin")
    45→///
    46→/// # Returns
    47→/// * `Result<TemplateMetadata>` - The template metadata
    48→///
    49→/// # Example
    50→/// ```no_run
    51→/// use templateflow::api::get_metadata;
    52→/// 
    53→/// let metadata = get_metadata("MNI152Lin").unwrap();
    54→/// println!("Template name: {}", metadata.name);
    55→/// ```
    56→pub fn get_metadata(template: &str) -> Result<TemplateMetadata> {
    57→    ensure_layout()?;
    58→    
    59→    let layout_guard = LAYOUT.lock().unwrap();
    60→    let layout = layout_guard.as_ref().unwrap();
    61→    
    62→    // First check if metadata exists in the skeleton
    63→    if let Some(metadata) = layout.get_metadata(template) {
    64→        return Ok(metadata.clone());
    65→    }
    66→    
    67→    // If not in skeleton, try to download template_description.json
    68→    let template_dir = CONFIG.home.join(format!("tpl-{}", template));
