    71→    // Download if not cached
    72→    if !metadata_path.exists() {
    73→        let s3_path = format!("tpl-{}/template_description.json", template);
    74→        s3::download_file_sync(&s3_path, &metadata_path, false)?;
    75→    }
    76→    
    77→    // Parse the metadata
    78→    TemplateMetadata::from_file(&metadata_path)
    79→}
