    90→    let metadata = get_metadata(template)?;
    91→    
    92→    let citations: Vec<String> = if bibtex {
    93→        // TODO: Implement BibTeX formatting
    94→        metadata.references_and_links
    95→            .iter()
    96→            .enumerate()
    97→            .map(|(idx, ref_val)| {
    98→                format!(
    99→                    "@misc{{{}{},\n  title = {{{}}},\n  note = {{{}}}\n}}",
   100→                    template,
   101→                    idx + 1,
   102→                    metadata.name,
   103→                    serde_json::to_string(ref_val).unwrap_or_default()
   104→                )
   105→            })
   106→            .collect()
