   117→/// List available templates
   118→///
   119→/// # Arguments
   120→/// * `query` - Optional query parameters as key-value pairs
   121→///
   122→/// # Returns
   123→/// * `Result<Vec<String>>` - List of template names
   124→///
   125→/// # Example
   126→/// ```no_run
   127→/// use templateflow::api::templates;
   128→/// use std::collections::HashMap;
   129→/// 
   130→/// // Get all templates
   131→/// let all_templates = templates(None).unwrap();
   132→/// 
   133→/// // Get templates with specific properties
   134→/// let mut query = HashMap::new();
   135→/// query.insert("res".to_string(), "01".to_string());
   136→/// let filtered_templates = templates(Some(&query)).unwrap();
   137→/// ```
   138→pub fn templates(query: Option<&HashMap<String, String>>) -> Result<Vec<String>> {
   139→    ensure_layout()?;
   140→    
   141→    let layout_guard = LAYOUT.lock().unwrap();
   142→    let layout = layout_guard.as_ref().unwrap();
   143→    
   144→    if let Some(query_params) = query {
   145→        // Get all files matching the query
   146→        let files = layout.query(query_params);
   147→        
   148→        // Extract unique template names
   149→        let mut template_set = std::collections::HashSet::new();
   150→        for file in files {
   151→            template_set.insert(file.template.clone());
   152→        }
   153→        
   154→        let mut templates: Vec<String> = template_set.into_iter().collect();
   155→        templates.sort();
   156→        Ok(templates)
   157→    } else {
   158→        // Return all templates
   159→        let mut templates: Vec<String> = layout.get_templates()
   160→            .into_iter()
   161→            .map(|s| s.to_string())
   162→            .collect();
   163→        templates.sort();
   164→        Ok(templates)
   165→    }
   166→}
   167→
   168→/// List files for a template with BIDS queries
   169→///
   170→/// # Arguments
   171→/// * `template` - Template identifier (e.g., "MNI152Lin")
   172→/// * `query` - Optional query parameters as key-value pairs
   173→///
   174→/// # Returns
   175→/// * `Result<Vec<PathBuf>>` - List of file paths matching the query
   176→///
   177→/// # Example
   178→/// ```no_run
   179→/// use templateflow::api::ls;
   180→/// use std::collections::HashMap;
   181→/// 
   182→/// // List all files for a template
   183→/// let files = ls("MNI152Lin", None).unwrap();
   184→/// 
   185→/// // List files with specific resolution and suffix
   186→/// let mut query = HashMap::new();
   187→/// query.insert("res".to_string(), "01".to_string());
   188→/// query.insert("suffix".to_string(), "T1w".to_string());
   189→/// let filtered_files = ls("MNI152Lin", Some(&query)).unwrap();
   190→/// ```
   191→pub fn ls(template: &str, query: Option<&HashMap<String, String>>) -> Result<Vec<PathBuf>> {
   192→    ensure_layout()?;
   193→    
   194→    let layout_guard = LAYOUT.lock().unwrap();
   195→    let layout = layout_guard.as_ref().unwrap();
   196→    
   197→    // Build query with template
   198→    let mut full_query = HashMap::new();
   199→    full_query.insert("tpl".to_string(), template.to_string());
   200→    
   201→    // Add additional query parameters if provided
   202→    if let Some(params) = query {
   203→        for (key, value) in params {
   204→            full_query.insert(key.clone(), value.clone());
   205→        }
   206→    }
   207→    
   208→    // Query the layout
   209→    let files = layout.query(&full_query);
   210→    
   211→    if files.is_empty() {
   212→        return Err(TemplateFlowError::NoFilesMatched);
   213→    }
   214→    
   215→    // Convert to paths
   216→    let paths: Vec<PathBuf> = files.into_iter()
   217→        .map(|f| f.path.clone())
   218→        .collect();
   219→    
   220→    Ok(paths)
   221→}
   222→
   223→/// Download and return file paths for a template
   224→///
   225→/// # Arguments
   226→/// * `template` - Template identifier (e.g., "MNI152Lin")
   227→/// * `query` - Optional query parameters as key-value pairs
   228→///
   229→/// # Returns
   230→/// * `Result<Vec<PathBuf>>` - List of downloaded file paths
   231→///
   232→/// # Example
   233→/// ```no_run
   234→/// use templateflow::api::get;
   235→/// use std::collections::HashMap;
   236→/// 
   237→/// // Download all files for a template
   238→/// let files = get("MNI152Lin", None).unwrap();
   239→/// 
   240→/// // Download specific files
   241→/// let mut query = HashMap::new();
   242→/// query.insert("res".to_string(), "01".to_string());
   243→/// query.insert("suffix".to_string(), "T1w".to_string());
   244→/// let files = get("MNI152Lin", Some(&query)).unwrap();
   245→/// ```
   246→pub fn get(template: &str, query: Option<&HashMap<String, String>>) -> Result<Vec<PathBuf>> {
   247→    // First list the files
   248→    let files = ls(template, query)?;
   249→    
   250→    // Download each file
   251→    let mut downloaded_paths = Vec::new();
   252→    
   253→    for file_path in files {
   254→        // Construct local path
   255→        let local_path = CONFIG.home.join(&file_path);
   256→        
   257→        // Skip if already exists
   258→        if local_path.exists() {
   259→            downloaded_paths.push(local_path);
   260→            continue;
   261→        }
   262→        
   263→        // Download the file using the path relative to S3 root
   264→        s3::download_file_sync(&file_path.to_string_lossy(), &local_path, true)?;
   265→        downloaded_paths.push(local_path);
   266→    }
   267→    
   268→    Ok(downloaded_paths)
   269→}
   270→
   271→/// Asynchronously download and return file paths for a template
   272→///
   273→/// # Arguments
   274→/// * `template` - Template identifier (e.g., "MNI152Lin")
   275→/// * `query` - Optional query parameters as key-value pairs
   276→///
   277→/// # Returns
   278→/// * `Result<Vec<PathBuf>>` - List of downloaded file paths
   279→///
   280→/// # Example
   281→/// ```no_run
   282→/// use templateflow::api::get_async;
   283→/// use std::collections::HashMap;
   284→/// 
   285→/// # async fn example() -> Result<(), Box<dyn std::error::Error>> {
   286→/// // Download all files for a template
   287→/// let files = get_async("MNI152Lin", None).await?;
   288→/// 
   289→/// // Download specific files
   290→/// let mut query = HashMap::new();
   291→/// query.insert("res".to_string(), "01".to_string());
   292→/// query.insert("suffix".to_string(), "T1w".to_string());
   293→/// let files = get_async("MNI152Lin", Some(&query)).await?;
   294→/// # Ok(())
   295→/// # }
   296→/// ```
   297→pub async fn get_async(template: &str, query: Option<&HashMap<String, String>>) -> Result<Vec<PathBuf>> {
   298→    // First list the files
   299→    let files = ls(template, query)?;
   300→    
   301→    // Download each file
   302→    let mut downloaded_paths = Vec::new();
   303→    
   304→    for file_path in files {
   305→        // Construct local path
   306→        let local_path = CONFIG.home.join(&file_path);
   307→        
   308→        // Skip if already exists
   309→        if local_path.exists() {
   310→            downloaded_paths.push(local_path);
   311→            continue;
   312→        }
   313→        
   314→        // Download the file using the path relative to S3 root
   315→        s3::download_file(&file_path.to_string_lossy(), &local_path, true).await?;
   316→        downloaded_paths.push(local_path);
   317→    }
   318→    
   319→    Ok(downloaded_paths)
   320→}
   321→
   322→/// Asynchronously download multiple files concurrently
   323→///
   324→/// This function downloads multiple files in parallel for better performance
   325→/// when downloading many files.
   326→///
   327→/// # Arguments
   328→/// * `template` - Template identifier (e.g., "MNI152Lin")
   329→/// * `query` - Optional query parameters as key-value pairs
   330→///
   331→/// # Returns
   332→/// * `Result<Vec<PathBuf>>` - List of downloaded file paths
   333→///
   334→/// # Example
   335→/// ```no_run
   336→/// use templateflow::api::get_multiple_async;
   337→/// use std::collections::HashMap;
   338→/// 
   339→/// # async fn example() -> Result<(), Box<dyn std::error::Error>> {
   340→/// // Download multiple files concurrently
   341→/// let mut query = HashMap::new();
   342→/// query.insert("res".to_string(), "01".to_string());
   343→/// let files = get_multiple_async("MNI152Lin", Some(&query)).await?;
   344→/// # Ok(())
   345→/// # }
   346→/// ```
   347→pub async fn get_multiple_async(template: &str, query: Option<&HashMap<String, String>>) -> Result<Vec<PathBuf>> {
   348→    use futures::future::join_all;
   349→    
   350→    // First list the files
   351→    let files = ls(template, query)?;
   352→    
   353→    // Prepare download tasks
   354→    let mut download_tasks = Vec::new();
   355→    let mut already_cached = Vec::new();
   356→    
   357→    for file_path in files {
   358→        // Construct local path
   359→        let local_path = CONFIG.home.join(&file_path);
   360→        
   361→        // Skip if already exists
   362→        if local_path.exists() {
   363→            already_cached.push(local_path);
   364→            continue;
   365→        }
   366→        
   367→        // Create download task
   368→        let s3_path = file_path.to_string_lossy().to_string();
   369→        let local_path_clone = local_path.clone();
   370→        let download_task = async move {
   371→            s3::download_file(&s3_path, &local_path_clone, true).await?;
   372→            Ok::<PathBuf, TemplateFlowError>(local_path_clone)
   373→        };
   374→        
   375→        download_tasks.push(download_task);
   376→    }
   377→    
   378→    // Execute all downloads concurrently
   379→    let download_results = join_all(download_tasks).await;
   380→    
   381→    // Collect results
   382→    let mut downloaded_paths = already_cached;
   383→    for result in download_results {
   384→        downloaded_paths.push(result?);
   385→    }
   386→    
   387→    Ok(downloaded_paths)
   388→}

