//! Error types for the TemplateFlow library
//!
//! This module defines the error types that can be returned by TemplateFlow operations.

use thiserror::Error;

/// Main error type for TemplateFlow operations
///
/// This enum represents all possible errors that can occur when using the TemplateFlow library.
#[derive(Error, Debug)]
pub enum TemplateFlowError {
    /// The requested template was not found in the repository
    #[error("Template not found: {0}")]
    TemplateNotFound(String),

    /// No files matched the provided query parameters
    #[error("No files matched query")]
    NoFilesMatched,

    /// An error occurred during file download from S3
    #[error("Download failed: {0}")]
    DownloadError(#[from] reqwest::Error),

    /// An I/O error occurred (file system operations)
    #[error("IO error: {0}")]
    IoError(#[from] std::io::Error),

    /// An invalid BIDS entity was provided in a query
    #[error("Invalid BIDS entity: {0}")]
    InvalidEntity(String),

    /// An error occurred with the local cache
    #[error("Cache error: {0}")]
    CacheError(String),

    /// JSON parsing error (usually when reading metadata)
    #[error("JSON parsing error: {0}")]
    JsonError(#[from] serde_json::Error),

    /// URL parsing error
    #[error("URL parsing error: {0}")]
    UrlError(#[from] url::ParseError),

    /// Configuration error (e.g., invalid environment variable)
    #[error("Configuration error: {0}")]
    ConfigError(String),
}

/// Type alias for Results with TemplateFlowError
///
/// This type alias makes it more convenient to use the Result type throughout
/// the library without having to specify the error type each time.
///
/// # Example
/// ```
/// use templateflow::Result;
///
/// fn my_function() -> Result<String> {
///     Ok("success".to_string())
/// }
/// ```
pub type Result<T> = std::result::Result<T, TemplateFlowError>;

