//! BIDS layout and query implementation
//!
//! This module provides functionality for parsing BIDS entities
//! and querying templates based on BIDS conventions.

use crate::error::{Result, TemplateFlowError};
use serde::{Deserialize, Serialize};
use serde_json::Value;
use std::collections::HashMap;
use std::path::{Path, PathBuf};

/// BIDS entities that can be present in a filename
#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub enum BidsEntity {
    Template,
    Resolution,
    Density,
    Atlas,
    Suffix,
    Description,
    Extension,
    Label,
    Segmentation,
    Hemisphere,
    Space,
}

impl BidsEntity {
    /// Get the short form used in filenames (e.g., "res" for Resolution)
    pub fn key(&self) -> &'static str {
        match self {
            BidsEntity::Template => "tpl",
            BidsEntity::Resolution => "res",
            BidsEntity::Density => "den",
            BidsEntity::Atlas => "atlas",
            BidsEntity::Suffix => "suffix",
            BidsEntity::Description => "desc",
            BidsEntity::Extension => "ext",
            BidsEntity::Label => "label",
            BidsEntity::Segmentation => "seg",
            BidsEntity::Hemisphere => "hemi",
            BidsEntity::Space => "space",
        }
    }

    /// Parse from a key string
    pub fn from_key(key: &str) -> Option<Self> {
        match key {
            "tpl" => Some(BidsEntity::Template),
            "res" => Some(BidsEntity::Resolution),
            "den" => Some(BidsEntity::Density),
            "atlas" => Some(BidsEntity::Atlas),
            "suffix" => Some(BidsEntity::Suffix),
            "desc" => Some(BidsEntity::Description),
            "ext" => Some(BidsEntity::Extension),
            "label" => Some(BidsEntity::Label),
            "seg" => Some(BidsEntity::Segmentation),
            "hemi" => Some(BidsEntity::Hemisphere),
            "space" => Some(BidsEntity::Space),
            _ => None,
        }
    }
}

/// Template metadata from template_description.json
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "PascalCase")]
pub struct TemplateMetadata {
    /// Template identifier (e.g., "MNI152Lin")
    #[serde(rename = "Identifier")]
    pub identifier: Option<String>,

    /// Full name of the template
    #[serde(rename = "Name")]
    pub name: String,

    /// Description of the template
    #[serde(rename = "Description")]
    pub description: Option<String>,

    /// Native coordinate system (e.g., "MNI152Lin")
    #[serde(rename = "NativeCoordinateSystem")]
    pub native_coord_system: Option<String>,

    /// List of authors
    #[serde(rename = "Authors", default)]
    pub authors: Vec<String>,

    /// License information
    #[serde(rename = "License")]
    pub license: Option<String>,

    /// List of references and links
    #[serde(rename = "ReferencesAndLinks", default)]
    pub references_and_links: Vec<Value>,

    /// URL to the template
    #[serde(rename = "URL")]
    pub url: Option<String>,

    /// DOI of the template
    #[serde(rename = "DOI")]
    pub doi: Option<String>,

    /// Version of the template
    #[serde(rename = "Version")]
    pub version: Option<String>,

    /// Research Resource Identifier
    #[serde(rename = "RRID")]
    pub rrid: Option<String>,

    /// Species (e.g., "Homo sapiens")
    #[serde(rename = "Species")]
    pub species: Option<String>,

    /// Any additional fields not explicitly defined
    #[serde(flatten)]
    pub extra: HashMap<String, Value>,
}

impl TemplateMetadata {
    /// Parse metadata from JSON string
    pub fn from_json(json: &str) -> Result<Self> {
        serde_json::from_str(json)
            .map_err(|e| TemplateFlowError::InvalidEntity(format!("Invalid metadata JSON: {}", e)))
    }

    /// Parse metadata from a file
    pub fn from_file(path: &Path) -> Result<Self> {
        let content = std::fs::read_to_string(path)?;
        Self::from_json(&content)
    }
}

/// A single file in the template layout
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct TemplateFile {
    /// Full path to the file
    pub path: PathBuf,
    /// Template name
    pub template: String,
    /// BIDS entities extracted from the filename
    pub entities: HashMap<String, String>,
    /// File suffix (e.g., "T1w", "mask", "dseg")
    pub suffix: Option<String>,
    /// File extension (e.g., "nii.gz", "json", "tsv")
    pub extension: Option<String>,
}

impl TemplateFile {
    /// Create a new TemplateFile by parsing a path
    pub fn from_path(path: &Path) -> Result<Self> {
        let filename = path
            .file_name()
            .and_then(|n| n.to_str())
            .ok_or_else(|| TemplateFlowError::InvalidEntity("Invalid filename".to_string()))?;

        let entities = parse_entities(filename)?;

        let template = entities
            .get("tpl")
            .ok_or_else(|| TemplateFlowError::InvalidEntity("Missing template entity".to_string()))?
            .clone();

        let suffix = extract_suffix(filename);
        let extension = extract_extension(filename);

        Ok(TemplateFile {
            path: path.to_path_buf(),
            template,
            entities,
            suffix,
            extension,
        })
    }

    /// Check if this file matches the given query parameters
    pub fn matches(&self, query: &HashMap<String, String>) -> bool {
        for (key, value) in query {
            match key.as_str() {
                "suffix" => {
                    if self.suffix.as_ref() != Some(value) {
                        return false;
                    }
                }
                "extension" => {
                    if self.extension.as_ref() != Some(value) {
                        return false;
                    }
                }
                _ => {
                    if self.entities.get(key) != Some(value) {
                        return false;
                    }
                }
            }
        }
        true
    }
}

/// Parse BIDS entities from a filename
fn parse_entities(filename: &str) -> Result<HashMap<String, String>> {
    let mut entities = HashMap::new();

    // Remove extension(s) to get the base name
    let base = filename.split('.').next().unwrap_or(filename);

    // Split by underscore to get entity pairs
    let parts: Vec<&str> = base.split('_').collect();

    for part in parts {
        if let Some(dash_pos) = part.find('-') {
            let key = &part[..dash_pos];
            let value = &part[dash_pos + 1..];

            // Validate that this is a known entity
            if BidsEntity::from_key(key).is_some() {
                entities.insert(key.to_string(), value.to_string());
            }
        }
    }

    Ok(entities)
}

/// Extract the suffix from a filename (last part after underscore, before extension)
fn extract_suffix(filename: &str) -> Option<String> {
    // Remove extensions
    let base = filename.split('.').next()?;

    // Get the last part after underscore
    let parts: Vec<&str> = base.split('_').collect();
    let last_part = parts.last()?;

    // If it doesn't contain a dash, it's likely a suffix
    if !last_part.contains('-') {
        Some(last_part.to_string())
    } else {
        None
    }
}

/// Extract the extension(s) from a filename (e.g., "nii.gz", "json")
fn extract_extension(filename: &str) -> Option<String> {
    if let Some(dot_pos) = filename.find('.') {
        Some(filename[dot_pos + 1..].to_string())
    } else {
        None
    }
}

/// Template layout containing all files for available templates
#[derive(Debug, Default, Serialize, Deserialize)]
pub struct TemplateLayout {
    /// Map from template name to list of files
    pub templates: HashMap<String, Vec<TemplateFile>>,

    /// Map from template name to metadata
    pub metadata: HashMap<String, TemplateMetadata>,
}

impl TemplateLayout {
    /// Create a new empty layout
    pub fn new() -> Self {
        Self::default()
    }

    /// Add a file to the layout
    pub fn add_file(&mut self, file: TemplateFile) {
        self.templates
            .entry(file.template.clone())
            .or_insert_with(Vec::new)
            .push(file);
    }

    /// Get all templates
    pub fn get_templates(&self) -> Vec<&str> {
        self.templates.keys().map(|s| s.as_str()).collect()
    }

    /// Get files for a specific template
    pub fn get_template_files(&self, template: &str) -> Option<&[TemplateFile]> {
        self.templates.get(template).map(|v| v.as_slice())
    }

    /// Query files across all templates
    pub fn query(&self, query: &HashMap<String, String>) -> Vec<&TemplateFile> {
        let mut results = Vec::new();

        // If template is specified in query, only search that template
        if let Some(template) = query.get("tpl") {
            if let Some(files) = self.templates.get(template) {
                for file in files {
                    if file.matches(query) {
                        results.push(file);
                    }
                }
            }
        } else {
            // Search all templates
            for files in self.templates.values() {
                for file in files {
                    if file.matches(query) {
                        results.push(file);
                    }
                }
            }
        }

        results
    }

    /// Add metadata for a template
    pub fn add_metadata(&mut self, template: &str, metadata: TemplateMetadata) {
        self.metadata.insert(template.to_string(), metadata);
    }

    /// Get metadata for a specific template
    pub fn get_metadata(&self, template: &str) -> Option<&TemplateMetadata> {
        self.metadata.get(template)
    }
}

/// Parse the templateflow skeleton from a zip file
pub fn parse_skeleton<R: std::io::Read + std::io::Seek>(reader: R) -> Result<TemplateLayout> {
    use zip::ZipArchive;
    use std::io::Read;

    let mut archive = ZipArchive::new(reader)
        .map_err(|e| TemplateFlowError::IoError(e.into()))?;

    let mut layout = TemplateLayout::new();
    let mut metadata_files = HashMap::new();

    // First pass: collect all files and metadata
    for i in 0..archive.len() {
        let mut file = archive.by_index(i)
            .map_err(|e| TemplateFlowError::IoError(e.into()))?;

        let path = PathBuf::from(file.name());

        // Skip directories
        if file.is_dir() {
            continue;
        }

        // Check if path is within a template directory
        let components: Vec<_> = path.components().collect();
        if components.is_empty() {
            continue;
        }

        // Get the first component (should be template directory)
        let first_component = components[0].as_os_str().to_str().unwrap_or("");
        if !first_component.starts_with("tpl-") {
            continue;
        }

        // Check if this is a template_description.json file
        if path.file_name() == Some(std::ffi::OsStr::new("template_description.json")) {
            // Extract template name from parent directory
            if let Some(parent) = path.parent() {
                if let Some(parent_name) = parent.file_name() {
                    if let Some(template_name) = parent_name.to_str() {
                        if template_name.starts_with("tpl-") {
                            let template = template_name.strip_prefix("tpl-").unwrap();
                            let mut content = String::new();
                            file.read_to_string(&mut content)
                                .map_err(|e| TemplateFlowError::IoError(e))?;
                            metadata_files.insert(template.to_string(), content);
                        }
                    }
                }
            }
        } else {
            // Try to parse as a template file
            match TemplateFile::from_path(&path) {
                Ok(template_file) => {
                    layout.add_file(template_file);
                }
                Err(_) => {
                    // Skip files that don't parse as valid BIDS files
                    continue;
                }
            }
        }
    }

    // Second pass: parse metadata files
    for (template, json_content) in metadata_files {
        match TemplateMetadata::from_json(&json_content) {
            Ok(metadata) => {
                layout.add_metadata(&template, metadata);
            }
            Err(e) => {
                // Log error but don't fail the entire parsing
                eprintln!("Failed to parse metadata for template {}: {}", template, e);
            }
        }
    }

    Ok(layout)
}

/// Load the skeleton from a file path
pub fn load_skeleton_from_file(path: &Path) -> Result<TemplateLayout> {
    use std::fs::File;

    let file = File::open(path)?;
    parse_skeleton(file)
}

/// Load the skeleton from bytes
pub fn load_skeleton_from_bytes(bytes: &[u8]) -> Result<TemplateLayout> {
    use std::io::Cursor;

    let cursor = Cursor::new(bytes);
    parse_skeleton(cursor)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_parse_entities() {
        let filename = "tpl-MNI152NLin2009cAsym_res-01_desc-brain_T1w.nii.gz";
        let entities = parse_entities(filename).unwrap();

        assert_eq!(entities.get("tpl"), Some(&"MNI152NLin2009cAsym".to_string()));
        assert_eq!(entities.get("res"), Some(&"01".to_string()));
        assert_eq!(entities.get("desc"), Some(&"brain".to_string()));
    }

    #[test]
    fn test_extract_suffix() {
        assert_eq!(
            extract_suffix("tpl-MNI152Lin_res-01_T1w.nii.gz"),
            Some("T1w".to_string())
        );
        assert_eq!(
            extract_suffix("tpl-MNI152Lin_res-01_desc-brain_mask.nii.gz"),
            Some("mask".to_string())
        );
        assert_eq!(
            extract_suffix("tpl-MNI152Lin_res-01_label-GM_probseg.nii.gz"),
            Some("probseg".to_string())
        );
    }

    #[test]
    fn test_extract_extension() {
        assert_eq!(
            extract_extension("file.nii.gz"),
            Some("nii.gz".to_string())
        );
        assert_eq!(
            extract_extension("template_description.json"),
            Some("json".to_string())
        );
        assert_eq!(extract_extension("no_extension"), None);
    }

    #[test]
    fn test_template_file_matches() {
        let file = TemplateFile {
            path: PathBuf::from("tpl-MNI152Lin_res-01_T1w.nii.gz"),
            template: "MNI152Lin".to_string(),
            entities: HashMap::from([
                ("tpl".to_string(), "MNI152Lin".to_string()),
                ("res".to_string(), "01".to_string()),
            ]),
            suffix: Some("T1w".to_string()),
            extension: Some("nii.gz".to_string()),
        };

        let query1 = HashMap::from([("res".to_string(), "01".to_string())]);
        assert!(file.matches(&query1));

        let query2 = HashMap::from([
            ("res".to_string(), "01".to_string()),
            ("suffix".to_string(), "T1w".to_string()),
        ]);
        assert!(file.matches(&query2));

        let query3 = HashMap::from([("res".to_string(), "02".to_string())]);
        assert!(!file.matches(&query3));
    }

    #[test]
    fn test_parse_skeleton() {
        // Test with actual skeleton file if it exists
        let skel_path = std::path::Path::new("../python-client/templateflow/conf/templateflow-skel.zip");
        assert!(skel_path.exists(), "Skeleton file not found at {:?}", skel_path);
        {
            let layout = load_skeleton_from_file(skel_path).unwrap();

            // Check that we have some templates
            assert!(!layout.templates.is_empty());

            // Check a known template exists
            assert!(layout.get_template_files("MNI152Lin").is_some());

            // Test querying
            let query = HashMap::from([
                ("tpl".to_string(), "MNI152Lin".to_string()),
                ("suffix".to_string(), "T1w".to_string()),
            ]);
            let results = layout.query(&query);
            assert!(!results.is_empty());

            // Test metadata
            println!("Total templates with metadata: {}", layout.metadata.len());
            if let Some(metadata) = layout.get_metadata("MNI152Lin") {
                assert!(!metadata.name.is_empty());
                println!("MNI152Lin metadata: {:?}", metadata);
            } else {
                println!("No metadata found for MNI152Lin");
            }
        }
    }

    #[test]
    fn test_template_metadata_parsing() {
        let json = r#"{
            "Name": "Linear ICBM Average Brain (ICBM152) Stereotaxic Registration Model",
            "Description": "The ICBM152 stereotaxic template for MNI space",
            "Identifier": "MNI152Lin",
            "License": "See LICENSE file",
            "Authors": ["Evans, A.C.", "Collins, D.L.", "Mills, S.R."],
            "ReferencesAndLinks": [
                {
                    "Reference": "Evans et al. 1992",
                    "URL": "https://doi.org/10.1234/example"
                }
            ],
            "Species": "Homo sapiens"
        }"#;

        let metadata = TemplateMetadata::from_json(json).unwrap();
        assert_eq!(metadata.name, "Linear ICBM Average Brain (ICBM152) Stereotaxic Registration Model");
        assert_eq!(metadata.identifier, Some("MNI152Lin".to_string()));
        assert_eq!(metadata.authors.len(), 3);
        assert_eq!(metadata.species, Some("Homo sapiens".to_string()));
    }
}

