    println!("Template: {}", metadata.name);
    println!("Authors: {}", metadata.authors.join(", "));

    // List all files
    let all_files = ls(template, None)?;
    println!("\nTotal files: {}", all_files.len());

    // List specific file types
    let mut query = HashMap::new();
    query.insert("suffix".to_string(), "mask".to_string());

    let masks = ls(template, Some(&query))?;
    println!("\nBrain masks:");
    for mask in &masks {
        println!("- {}", mask.display());
    }

    Ok(())
}
```

### 3. Downloading Template Files

```rust
use templateflow::get;
